193	    let dtype = options.dtype ?? custom_config.dtype;
194	    if (typeof dtype !== 'string') {
195	        if (dtype && dtype.hasOwnProperty(fileName)) {
196	            dtype = dtype[fileName];
197	        } else {
198	            dtype = DEFAULT_DEVICE_DTYPE_MAPPING[selectedDevice] ?? DATA_TYPES.fp32;
199	            console.warn(`dtype not specified for "${fileName}". Using the default dtype (${dtype}) for this device (${selectedDevice}).`);
200	        }
201	    }
202	
203	    if (dtype === DATA_TYPES.auto) {
204	        // Try to choose the auto dtype based on the custom config
205	        let config_dtype = custom_config.dtype;
206	        if (typeof config_dtype !== 'string') {
207	            config_dtype = config_dtype?.[fileName];
208	        }
