998	
999	        // By default, do not add special tokens, unless the tokenizer specifies otherwise
1000	        let add_special_tokens = generate_kwargs.add_special_tokens
1001	            ?? (this.tokenizer.add_bos_token || this.tokenizer.add_eos_token)
1002	            ?? false;
1003	
1004	        // Normalize inputs
1005	        /** @type {string[]} */
1006	        let inputs;
1007	        if (typeof texts === 'string') {
1008	            inputs = texts = [texts];
1009	        } else if (Array.isArray(texts) && texts.every(x => typeof x === 'string')) {
1010	            isBatched = true;
1011	            inputs = /** @type {string[]} */(texts);
1012	        } else {
1013	            if (isChat(texts)) {
1014	                texts = [/** @type {Chat} */(texts)];
1015	            } else if (Array.isArray(texts) && texts.every(isChat)) {
1016	                isBatched = true;
1017	            } else {
1018	                throw new Error('Input must be a string, an array of strings, a Chat, or an array of Chats');
1019	            }
1020	            isChatInput = true;
1021	
1022	            // If the input is a chat, we need to apply the chat template
1023	            inputs = /** @type {string[]} */(/** @type {Chat[]} */ (texts).map(
1024	                x => this.tokenizer.apply_chat_template(x, {
1025	                    tokenize: false,
1026	                    add_generation_prompt: true,
1027	                })
1028	            ));
1029	            add_special_tokens = false; // Chat template handles this already
1030	        }
1031	
1032	        // By default, return full text
1033	        const return_full_text = isChatInput
1034	            ? false
1035	            : generate_kwargs.return_full_text ?? true;
1036	
1037	        this.tokenizer.padding_side = 'left';
1038	        const text_inputs = this.tokenizer(inputs, {
1039	            add_special_tokens,
1040	            padding: true,
1041	            truncation: true,
1042	        });
1043	
1044	        const outputTokenIds = /** @type {Tensor} */(await this.model.generate({
1045	            ...text_inputs,
1046	            ...generate_kwargs
